import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useUserStore } from './userStore';
import { createCustomer } from './woocommerce';

const Login = () => {
  const navigate = useNavigate();
  const { setUser, isAuthenticated } = useUserStore();
  const [isLogin, setIsLogin] = useState(true);
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: '',
    name: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Redirect if already logged in
  React.useEffect(() => {
    if (isAuthenticated) {
      navigate('/my-account');
    }
  }, [isAuthenticated, navigate]);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      if (isLogin) {
        // Login logic - would need JWT authentication endpoint
        // For now, this is a placeholder
        setError('Login requires JWT authentication setup in WordPress');
      } else {
        // Register logic
        const customerData = {
          email: formData.email,
          username: formData.username,
          password: formData.password,
          first_name: formData.name.split(' ')[0],
          last_name: formData.name.split(' ').slice(1).join(' '),
          billing: {
            first_name: formData.name.split(' ')[0],
            email: formData.email
          }
        };

        const customer = await createCustomer(customerData);
        setUser(customer);
        navigate('/my-account');
      }
    } catch (err) {
      setError(isLogin ? 'Invalid credentials' : 'Registration failed');
      console.error('Auth error:', err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login">
      <header className="header">
        <div className="header-content">
          <h1>Ritchie Street Electronics</h1>
          <nav className="nav">
            <Link to="/">Home</Link>
            <Link to="/cart">Cart ({getCartCount()})</Link>
            <Link to="/login">Login</Link>
          </nav>
        </div>
      </header>

      <div className="auth-container">
        <div className="auth-box">
          <h2>{isLogin ? 'Login' : 'Register'}</h2>

          {error && <div className="error-message">{error}</div>}

          <form onSubmit={handleSubmit}>
            {!isLogin && (
              <>
                <div className="form-group">
                  <label>Full Name *</label>
                  <input
                    type="text"
                    name="name"
                    value={formData.name}
                    onChange={handleChange}
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Username *</label>
                  <input
                    type="text"
                    name="username"
                    value={formData.username}
                    onChange={handleChange}
                    required
                  />
                </div>
              </>
            )}

            <div className="form-group">
              <label>Email Address *</label>
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-group">
              <label>Password *</label>
              <input
                type="password"
                name="password"
                value={formData.password}
                onChange={handleChange}
                required
              />
            </div>

            <button type="submit" className="auth-btn" disabled={loading}>
              {loading ? 'Processing...' : (isLogin ? 'Login' : 'Register')}
            </button>
          </form>

          <div className="auth-switch">
            {isLogin ? (
              <p>
                Don't have an account?{' '}
                <button onClick={() => setIsLogin(false)}>Register</button>
              </p>
            ) : (
              <p>
                Already have an account?{' '}
                <button onClick={() => setIsLogin(true)}>Login</button>
              </p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
